const input = $('Workflow Input').item.json;
const products = $input.all();
const requestedVariant = (input.variant || '').toLowerCase();

if (!products || products.length === 0) {
  return [{
    json: {
      found: false,
      message: `Nie znaleziono produktów pasujących do "${input.product_name}".`
    }
  }];
}

const formatProduct = (product) => {
  let variants = product.variants;
  if (typeof variants === 'string') {
    variants = JSON.parse(variants);
  }

  // Filter variants by stock and optionally by requested variant
  let availableVariants = variants.filter(v => v.stock > 0);

  if (requestedVariant) {
    // Check if requested variant matches any available variant
    const matchingVariants = availableVariants.filter(v => {
      const variantStr = `${v.size} ${v.color}`.toLowerCase();
      return variantStr.includes(requestedVariant) || 
             requestedVariant.includes(v.size?.toLowerCase() || '') ||
             requestedVariant.includes(v.color?.toLowerCase() || '');
    });

    if (matchingVariants.length > 0) {
      availableVariants = matchingVariants;
    }
  }

  const variantsList = availableVariants.map(v => 
    `- ${v.size || ''} ${v.color || ''}: ${v.stock} szt. w magazynie`
  ).join('\n');

  const unavailableVariants = variants.filter(v => v.stock === 0);
  const unavailableList = unavailableVariants.length > 0 
    ? unavailableVariants.map(v => `- ${v.size || ''} ${v.color || ''}`).join('\n')
    : null;

  return {
    name: product.name,
    sku: product.sku,
    price: `${product.price} PLN`,
    category: product.category,
    description: product.description,
    url: product.url,
    available_variants: variantsList || 'Brak dostępnych wariantów',
    unavailable_variants: unavailableList,
    total_available_variants: availableVariants.length,
    is_available: availableVariants.length > 0
  };
};

const formattedProducts = products.map(p => formatProduct(p.json));

if (formattedProducts.length === 1) {
  const product = formattedProducts[0];
  return [{
    json: {
      found: true,
      single_product: true,
      ...product,
      message: product.is_available 
        ? `Produkt "${product.name}" jest dostępny.`
        : `Produkt "${product.name}" jest obecnie niedostępny.`
    }
  }];
} else {
  return [{
    json: {
      found: true,
      single_product: false,
      products_count: formattedProducts.length,
      products: formattedProducts.map(p => ({
        name: p.name,
        price: p.price,
        is_available: p.is_available,
        url: p.url
      })),
      message: `Znaleziono ${formattedProducts.length} produktów pasujących do "${input.product_name}".`
    }
  }];
}
